import type { CompileTimeMetadata, ObjectTypeDefinition, Osdk, PrimaryKeyType } from "@osdk/api";
export interface OptimisticBuilder {
	updateObject: <T extends ObjectTypeDefinition>(value: Osdk.Instance<T>) => this;
	createObject: <T extends ObjectTypeDefinition>(type: T, primaryKey: PrimaryKeyType<T>, properties: CompileTimeMetadata<T>["props"]) => this;
	deleteObject: <T extends ObjectTypeDefinition>(value: Osdk.Instance<T>) => this;
}
